UPDATE `user`
SET password = #{password}
WHERE email = #{email} AND status IN ('active', 'admin')

UPDATE user
SET profile_image = #{profileImage}
WHERE id = #{userId}

mapper.select:
SELECT COUNT(DISTINCT t.wit_user_id) FROM ( SELECT p.user_id AS wit_user_id FROM schedule s JOIN participation p ON p.schedule_id = s.id WHERE s.user_id = #{userId} AND s.status = 'completed' AND s.deleted_at IS NULL AND p.status = 'approved' AND p.user_id <> #{userId}
UNION
SELECT s.user_id AS wit_user_id FROM participation p JOIN schedule s ON s.id = p.schedule_id WHERE p.user_id = #{userId} AND p.status = 'approved' AND s.status = 'completed' AND s.deleted_at IS NULL AND s.user_id <> #{userId}
UNION
SELECT p2.user_id AS wit_user_id FROM participation p JOIN schedule s ON s.id = p.schedule_id JOIN participation p2 ON p2.schedule_id = s.id WHERE p.user_id = #{userId} AND p.status = 'approved' AND s.status = 'completed' AND s.deleted_at IS NULL AND p2.status = 'approved' AND p2.user_id <> #{userId} ) t
